const ev = $json;

// Em várias versões do n8n, o erro/nó vem em lugares diferentes:
const exec = ev.execution ?? {};
const err  = exec.error ?? ev.error ?? {};

// tenta achar o nó em múltiplos caminhos comuns
const nodeName =
  err?.node?.name ??
  err?.node?.type ??
  ev?.node?.name ??
  ev?.lastNodeExecuted ??
  "N/D";

// timestamp também varia; tenta vários e cai no agora
const rawTs =
  ev.timestamp ??
  ev.time ??
  exec.startedAt ??
  exec.stoppedAt ??
  new Date().toISOString();

const when = isNaN(new Date(rawTs).getTime())
  ? "N/D"
  : new Date(rawTs).toLocaleString("pt-BR");

const workflowName =
  ev.workflow?.name ??
  exec.workflowName ??
  ev.workflowName ??
  "N/D";

const executionId =
  exec.id ??
  ev.executionId ??
  "N/D";

const message =
  err.message ??
  err.description ??
  err.name ??
  "Sem mensagem de erro";

return [
  {
    json: {
      mensagem:
`🚨 *ERRO EM PRODUÇÃO*
📌 Workflow: ${workflowName}
🧩 Node: ${nodeName}
🕒 Data: ${when}

❌ Erro:
${message}

🆔 Execução:
${executionId}`
    }
  }
];

const e = $json;

return [
  {
    json: {
      mensagem:
`🚨 *ERRO EM PRODUÇÃO*
📌 Workflow: ${e.workflow?.name}
🧩 Node: ${e.node?.name}
🕒 Data: ${new Date(e.timestamp).toLocaleString("pt-BR")}

❌ Erro:
${e.error?.message}

🆔 Execução:
${e.execution?.id}`
    }
  }
];

